import { jsx } from 'react/jsx-runtime';
import { classNames } from '../../../../helpers/classnames.js';
import { useRef, useEffect } from 'react';

const ImageGallery = ({ selectedIndex, onClick, content }) => {
    const galleryRef = useRef(null);
    useEffect(() => {
        scrollIntoFrame(selectedIndex);
    }, [selectedIndex]);
    const scrollIntoFrame = index => {
        if (galleryRef.current) {
            const container = galleryRef.current;
            const selectedImg = container.children[index];
            const scrollLeft = selectedImg.offsetLeft - container.offsetWidth / 2 + selectedImg.offsetWidth / 2;
            container.scrollTo({
                left: scrollLeft,
                behavior: 'smooth',
            });
        }
    };
    const handleClickOnFrame = index => {
        onClick(index);
    };
    return (jsx("div", { className: "dsb_preview__gallery-img", ref: galleryRef, children: content.map((image, index) => (jsx("img", { className: classNames('dsb_preview__gallery-img__frame', selectedIndex === index && 'dsb_preview__gallery-img__frame-selected'), onClick: () => handleClickOnFrame(index), alt: image.alt, src: image.src }, index))) }));
};

export { ImageGallery };
